import{_ as a,o as n,c as e,a2 as p}from"./chunks/framework.C24VBsJ9.js";const u=JSON.parse('{"title":"U-Boot 调试命令","description":"","frontmatter":{"title":"U-Boot 调试命令"},"headers":[],"relativePath":"tutorial/uboot/09_debugging_commands.md","filePath":"tutorial/uboot/09_debugging_commands.md","lastUpdated":1781369075000}'),i={name:"tutorial/uboot/09_debugging_commands.md"};function l(t,s,r,c,d,o){return n(),e("div",null,[...s[0]||(s[0]=[p(`<h1 id="_2026正点原子开发板移植-uboot篇完结-u-boot调试命令-命令行是嵌入式开发的神器" tabindex="-1">2026正点原子开发板移植（UBoot篇完结）：U-Boot调试命令：命令行是嵌入式开发的神器 <a class="header-anchor" href="#_2026正点原子开发板移植-uboot篇完结-u-boot调试命令-命令行是嵌入式开发的神器" aria-label="Permalink to &quot;2026正点原子开发板移植（UBoot篇完结）：U-Boot调试命令：命令行是嵌入式开发的神器&quot;">​</a></h1><h2 id="板子信息查询-bdinfo-命令" tabindex="-1">板子信息查询：bdinfo 命令 <a class="header-anchor" href="#板子信息查询-bdinfo-命令" aria-label="Permalink to &quot;板子信息查询：bdinfo 命令&quot;">​</a></h2><p>当你拿到一块新板子，或者 U-Boot 启动后第一件事干什么？我的习惯是先看看板子的基本信息。这就像医生看病先要量体温血压一样，你得先知道板子的&quot;健康指标&quot;。</p><p><code>bdinfo</code> 命令就是用来查看板子信息的。敲一下这个命令，你会看到一堆信息冒出来：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; bdinfo</span></span>
<span class="line"><span>arch_number = 0x00000000</span></span>
<span class="line"><span>boot_params = 0x80000100</span></span>
<span class="line"><span>DRAM bank   = 0x00000000</span></span>
<span class="line"><span>-&gt; start    = 0x80000000</span></span>
<span class="line"><span>-&gt; size     = 0x20000000</span></span>
<span class="line"><span>flashstart  = 0x00000000</span></span>
<span class="line"><span>flashsize   = 0x00000000</span></span>
<span class="line"><span>flashoffset = 0x00000000</span></span>
<span class="line"><span>baudrate    = 115200 bps</span></span>
<span class="line"><span>relocaddr   = 0x9ff4a000</span></span>
<span class="line"><span>reloc off   = 0x17f4a000</span></span>
<span class="line"><span>Build       = 32-bit</span></span>
<span class="line"><span>current eth = fec-1:02</span></span>
<span class="line"><span>ethaddr     = 00:04:25:1c:a0:00</span></span>
<span class="line"><span>IP addr     = 192.168.1.102</span></span>
<span class="line"><span>fdt_blob    = 0x88000000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>别慌，我们来拆一下这些信息都是什么意思。</p><p><code>arch_number</code> 是架构号，这个在老版本 U-Boot 里用来传递给内核告诉它自己的机器类型，现在用设备树了基本不怎么用。<code>boot_params</code> 是启动参数的地址，内核会从这里读取参数。<code>DRAM bank</code> 显示内存信息，i.MX6ULL 有一块 512MB 的 DDR，起始地址 0x80000000，这个信息很关键，如果你要手动加载内核到内存，得知道哪块内存区域是可用的。</p><p><code>baudrate</code> 是串口波特率，默认 115200，如果你发现串口输出乱码，第一件事就是检查波特率对不对。<code>relocaddr</code> 和 <code>reloc off</code> 是 U-Boot 自己的重定位信息，U-Boot 启动后会把自己从 Flash 复制到 DDR 里运行，这两个值告诉你复制到了哪里。<code>Build</code> 告诉你这是 32 位还是 64 位构建，i.MX6ULL 是 32 位 ARM 架构。</p><p>网络信息是重点，<code>current eth</code> 显示当前使用的网卡设备，<code>ethaddr</code> 是 MAC 地址，<code>IP addr</code> 是 IP 地址。如果你要调试网络相关的问题，比如 tftp 启动失败，第一步就是检查这些信息对不对。<code>fdt_blob</code> 是设备树树的地址，后面我们会详细讲怎么用 fdt 命令操作它。</p><p>bdinfo 还有一些参数选项。<code>bdinfo -a</code> 显示所有信息，<code>bdinfo -e</code> 只显示网络信息，<code>bdinfo -m</code> 只显示内存信息。这些选项在你只需要看某类信息时很有用，不用在一堆输出里翻来翻去。</p><p>我来举一个实际场景。有一次我调试一块板子，tftp 总是超时，换了网线换了交换机都不行。后来用 <code>bdinfo -e</code> 一看，发现 IP 地址是 0.0.0.0，根本没有分配到地址。原来是 <code>ipaddr</code> 环境变量没设置，设置一下就好了。你看，如果一上来就瞎改网络配置，可能折腾半天也找不到问题，用 bdinfo 看一眼就清楚了。</p><h2 id="存储操作-mmc-命令家族" tabindex="-1">存储操作：mmc 命令家族 <a class="header-anchor" href="#存储操作-mmc-命令家族" aria-label="Permalink to &quot;存储操作：mmc 命令家族&quot;">​</a></h2><p>存储是嵌入式系统的基石，eMMC、SD 卡这些是 U-Boot 启动和加载文件的关键。<code>mmc</code> 命令家族是你与存储设备打交道的工具箱。</p><h3 id="mmc-info-和-mmc-dev" tabindex="-1">mmc info 和 mmc dev <a class="header-anchor" href="#mmc-info-和-mmc-dev" aria-label="Permalink to &quot;mmc info 和 mmc dev&quot;">​</a></h3><p>最基础的是 <code>mmc info</code> 命令，它会显示当前 MMC 设备的详细信息：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; mmc info</span></span>
<span class="line"><span>Device: FSL_SDHC</span></span>
<span class="line"><span>Manufacturer ID: 11</span></span>
<span class="line"><span>OEM: 149</span></span>
<span class="line"><span>Name: SD8GAA</span></span>
<span class="line"><span>Bus Speed: 52000000</span></span>
<span class="line"><span>Mode: MMC HS DDR</span></span>
<span class="line"><span>Rd Block Len: 512</span></span>
<span class="line"><span>MMC version 5.1</span></span>
<span class="line"><span>High Capacity: Yes</span></span>
<span class="line"><span>Capacity: 7.3 GiB</span></span>
<span class="line"><span>Bus Width: 8-bit DDR</span></span>
<span class="line"><span>Erase Group Size: 512 KiB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>这些信息告诉你存储设备的&quot;身份&quot;。 Manufacturer ID 和 OEM 可以帮你识别用的是哪家的芯片，Bus Speed 和 Mode 显示当前传输速度和模式，Capacity 显示容量，Bus Width 显示数据位宽。如果你换了不同容量的 eMMC，或者换了不同厂商的芯片，用这个命令可以确认硬件识别是否正确。</p><p>默认情况下，mmc 命令操作的是当前设备。如果你有多个 MMC 设备，比如一个 SD 卡和一个 eMMC，需要用 <code>mmc dev</code> 切换：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; mmc dev 0    # 切换到设备 0</span></span>
<span class="line"><span>=&gt; mmc dev 1    # 切换到设备 1</span></span>
<span class="line"><span>=&gt; mmc dev      # 不带参数显示当前设备</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>i.MX6ULL 上通常设备 0 是 SD 卡，设备 1 是 eMMC，但这个要看具体的板子设计，不确定的话就用 <code>mmc list</code> 命令查看所有设备：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; mmc list</span></span>
<span class="line"><span>FSL_SDHC: 0 (eMMC)</span></span>
<span class="line"><span>FSL_SDHC: 1 (SD)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="mmc-rescan-和-mmc-part" tabindex="-1">mmc rescan 和 mmc part <a class="header-anchor" href="#mmc-rescan-和-mmc-part" aria-label="Permalink to &quot;mmc rescan 和 mmc part&quot;">​</a></h3><p>有时候你插拔了 SD 卡，或者热插拔了存储设备，U-Boot 不知道设备状态变了，这时候用 <code>mmc rescan</code> 重新扫描：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; mmc rescan</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个命令会重新初始化 MMC 控制器，重新读取设备信息。如果你发现读取操作失败，或者设备容量显示不对，试试这个命令。</p><p><code>mmc part</code> 命令显示分区表：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; mmc part</span></span>
<span class="line"><span>Partition Map for MMC device 1  --   Partition Type: DOS</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Part    Start LBA       Size                Type</span></span>
<span class="line"><span>  1     0x00000022      0x0007ffa0         0x83 Linux</span></span>
<span class="line"><span>  2     0x0007ffc2      0x0017ffa8         0x83 Linux</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这里显示的是 DOS 分区表，有两个 Linux 分区。如果你看到分区表为空或者分区类型不对，可能是烧录出了问题，或者分区表损坏了。</p><h3 id="mmc-read-和-mmc-write" tabindex="-1">mmc read 和 mmc write <a class="header-anchor" href="#mmc-read-和-mmc-write" aria-label="Permalink to &quot;mmc read 和 mmc write&quot;">​</a></h3><p>读取和写入是核心操作。<code>mmc read</code> 从存储设备读取数据到内存：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; mmc read &lt;addr&gt; &lt;blk#&gt; &lt;cnt&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>addr</code> 是目标内存地址，<code>blk#</code> 是起始块号，<code>cnt</code> 是要读取的块数。MMC 设备通常以 512 字节为一个块，所以计算地址的时候要考虑这个。举个例子，要把 eMMC 的第一个块读到内存 0x88000000：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; mmc read 0x88000000 0x0 0x1</span></span>
<span class="line"><span>MMC read: dev # 1, block # 0, count 1 ... 1 blocks read: OK</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>mmc write</code> 是反向操作，从内存写入到存储设备：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; mmc write &lt;addr&gt; &lt;blk#&gt; &lt;cnt&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个命令要慎用，写错了位置可能把 bootloader 或者分区表覆盖掉。一个安全做法是先用 <code>mmc read</code> 读取一下看看内容对不对，确认无误后再写。</p><p>有个实战技巧：你可以用 <code>mmc read</code> 把整个镜像加载到内存，然后用 <code>iminfo</code> 命令验证镜像格式，确认没问题后再用 <code>mmc write</code> 写回去。这比直接烧录安全多了，至少你知道烧的是什么。</p><h3 id="mmc-erase-和-mmc-bootbus" tabindex="-1">mmc erase 和 mmc bootbus <a class="header-anchor" href="#mmc-erase-和-mmc-bootbus" aria-label="Permalink to &quot;mmc erase 和 mmc bootbus&quot;">​</a></h3><p><code>mmc erase</code> 擦除存储区域：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; mmc erase &lt;blk#&gt; &lt;cnt&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个命令在某些场景下很有用，比如你想清空某个分区，或者测试坏块。不过要注意，eMMC 有擦写寿命，别没事就擦来擦去。</p><p><code>mmc bootbus</code> 设置启动总线配置，这个主要和安全启动相关：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; mmc bootbus 1 2 1 0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>四个参数分别是设备号、数据宽度、强制总线模式、保留位。如果你要做安全启动，可能需要配置这个，但大部分应用场景用不上。</p><h2 id="网络启动-tftp-和-dhcp-命令" tabindex="-1">网络启动：tftp 和 dhcp 命令 <a class="header-anchor" href="#网络启动-tftp-和-dhcp-命令" aria-label="Permalink to &quot;网络启动：tftp 和 dhcp 命令&quot;">​</a></h2><p>网络启动是嵌入式开发的神技。你想想，每次改了内核或者设备树，都要烧录到 eMMC，多麻烦啊。用网络启动，文件放在服务器上，板子启动时自动下载，改完代码重启就行，开发效率提升一大截。</p><h3 id="dhcp-命令" tabindex="-1">dhcp 命令 <a class="header-anchor" href="#dhcp-命令" aria-label="Permalink to &quot;dhcp 命令&quot;">​</a></h3><p><code>dhcp</code> 命令通过 DHCP 协议获取 IP 地址，并可选地下载启动文件：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; dhcp</span></span>
<span class="line"><span>BOOTP broadcast 1</span></span>
<span class="line"><span>BOOTP broadcast 2</span></span>
<span class="line"><span>DHCP client bound to address 192.168.1.102 (1033 ms)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>这是最简单的用法，只获取 IP 地址。如果你还想自动下载文件，可以在服务器上配置 BOOTP 文件名，或者在命令里指定：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; dhcp 0x82000000 zImage</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这会在获取 IP 后，自动把 zImage 下载到 0x82000000 地址。不过我一般不用这种方式，因为不够灵活，我喜欢先用 dhcp 获取 IP，然后手动用 tftp 下载文件。</p><p>dhcp 的 IP 分配过程很简单。板子广播一个 DHCP 请求，DHCP 服务器响应一个 offer 包，包含 IP 地址、子网掩码、网关等信息，板子发送请求确认，服务器响应确认完成分配。这个过程通常几百毫秒就能完成。</p><p>如果你发现 dhcp 获取不到 IP，先检查网线插好了没，再用 <code>bdinfo -e</code> 看看网卡驱动是不是加载了。如果还不行，可能是 DHCP 服务器配置问题，看看服务器日志。</p><h3 id="tftp-命令" tabindex="-1">tftp 命令 <a class="header-anchor" href="#tftp-命令" aria-label="Permalink to &quot;tftp 命令&quot;">​</a></h3><p><code>tftp</code> 命令通过 TFTP 协议下载文件：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; tftp 0x82000000 zImage</span></span>
<span class="line"><span>Using ethernet@02188000 device</span></span>
<span class="line"><span>TFTP from server 192.168.1.1; our IP address is 192.168.1.102</span></span>
<span class="line"><span>Filename &#39;zImage&#39;.</span></span>
<span class="line"><span>Load address: 0x82000000</span></span>
<span class="line"><span>Loading: #################################################################</span></span>
<span class="line"><span>         6.2 MiB/s</span></span>
<span class="line"><span>done</span></span>
<span class="line"><span>Bytes transferred = 6821504 (6824d0 hex)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>这个命令会从 TFTP 服务器下载 zImage 到内存 0x82000000。下载速度取决于网络状况，你看到的这个 6.2 MB/s 已经很快了，百兆网络理论速度也就 12.5 MB/s，实际能达到 6-8 MB/s 就很不错了。</p><p>tftp 服务器怎么搭建？Linux 下最简单的是用 <code>tftpd-hpa</code>：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tftpd-hpa</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tftpd-hpa</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>把文件放到 <code>/var/lib/tftpboot/</code> 目录下就行了。Windows 下可以用 tftpd32 或者 FileZilla Server，都很简单。</p><p>TFTP 是基于 UDP 的，所以不保证可靠传输，但实现简单，资源占用少，非常适合嵌入式场景。不过要注意，TFTP 不支持大于 32MB 的文件，如果你要下载更大的东西，得用 NFS 或者 HTTP。</p><h3 id="网络调试技巧" tabindex="-1">网络调试技巧 <a class="header-anchor" href="#网络调试技巧" aria-label="Permalink to &quot;网络调试技巧&quot;">​</a></h3><p>网络启动常见问题无非这么几个：获取不到 IP、下载超时、下载后校验失败。获取不到 IP 先检查网线和 DHCP 服务器，下载超时先检查防火墙和文件路径，校验失败可能是传输错误，重新下载试试。</p><p>有个实用技巧是用 <code>ping</code> 命令测试网络连通性：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; ping 192.168.1.1</span></span>
<span class="line"><span>Using ethernet@02188000 device</span></span>
<span class="line"><span>host 192.168.1.1 is alive</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>如果 ping 不通，说明网络配置有问题，不用浪费时间尝试 tftp。还要注意，U-Boot 的 <code>ping</code> 命令只发送几个包就停止了，不像 Linux 的 ping 会一直跑，这是正常行为。</p><p>调试网络问题时，<code>printenv</code> 命令也很有用，看看 <code>ipaddr</code>、<code>serverip</code>、<code>netmask</code> 这些环境变量设置对不对：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; printenv ipaddr serverip netmask</span></span>
<span class="line"><span>ipaddr=192.168.1.102</span></span>
<span class="line"><span>serverip=192.168.1.1</span></span>
<span class="line"><span>netmask=255.255.255.0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>如果这些值不对，用 <code>setenv</code> 修改一下，然后 <code>saveenv</code> 保存。</p><h2 id="内核启动-bootm-和-bootz-命令" tabindex="-1">内核启动：bootm 和 bootz 命令 <a class="header-anchor" href="#内核启动-bootm-和-bootz-命令" aria-label="Permalink to &quot;内核启动：bootm 和 bootz 命令&quot;">​</a></h2><p>U-Boot 的终极目标是启动内核。<code>bootm</code> 和 <code>bootz</code> 是两个最常用的启动命令，区别在于支持的镜像格式。<code>bootm</code> 启动 uImage 格式（老式的 Legacy Image），<code>bootz</code> 启动 zImage 格式（ARM Linux 的压缩内核镜像）。</p><h3 id="bootz-命令" tabindex="-1">bootz 命令 <a class="header-anchor" href="#bootz-命令" aria-label="Permalink to &quot;bootz 命令&quot;">​</a></h3><p>先说 <code>bootz</code>，因为现在大部分 ARM 系统都用 zImage。基本用法：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; bootz 0x82000000 - 0x88000000</span></span>
<span class="line"><span>Kernel image @ 0x82000000 [ 0x000000 - 0x68238f ]</span></span>
<span class="line"><span>## Flattened Device Tree blob at 0x88000000</span></span>
<span class="line"><span>   Booting using the fdt blob at 0x88000000</span></span>
<span class="line"><span>   Loading Device Tree to 0x87fff000, end 0x88005b9f ... OK</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Starting kernel ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>三个参数分别是：内核地址、initrd 地址（用 <code>-</code> 表示没有）、设备树地址。内核地址就是你用 tftp 下载到的地址，设备树地址通常是加载地址后面的某个位置。</p><p><code>bootz</code> 会先解压内核，然后设置启动参数，最后跳到内核入口点执行。解压这个过程需要一点时间，你会看到一段时间的&quot;黑屏&quot;，这是正常的，内核在初始化早期还没有串口输出。</p><p>如果启动失败，<code>bootz</code> 会停住并显示错误信息。最常见的问题是解压失败、设备树格式不对、内存地址冲突。错误信息会给出一些线索，比如 &quot;Bad magic number&quot; 表示镜像格式不对，&quot;CRC error&quot; 表示文件损坏，重新下载试试。</p><h3 id="bootm-命令" tabindex="-1">bootm 命令 <a class="header-anchor" href="#bootm-命令" aria-label="Permalink to &quot;bootm 命令&quot;">​</a></h3><p><code>bootm</code> 的用法类似，但支持更多镜像格式：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; bootm 0x82000000</span></span>
<span class="line"><span>## Booting kernel from Legacy Image at 0x82000000 ...</span></span>
<span class="line"><span>   Image Name:   Linux-5.15.0</span></span>
<span class="line"><span>   Image Type:   ARM Linux Kernel Image (uncompressed)</span></span>
<span class="line"><span>   Data Size:    6821504 Bytes = 6.5 MiB</span></span>
<span class="line"><span>   Load Address: 0x80008000</span></span>
<span class="line"><span>   Entry Point:  0x80008000</span></span>
<span class="line"><span>   Verifying Checksum ... OK</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><code>bootm</code> 会先检查镜像头，验证 CRC 校验和，然后根据镜像类型决定如何处理。uImage 格式包含一个头，记录了镜像类型、加载地址、入口点等信息，<code>bootm</code> 根据这些信息正确加载和启动。</p><p><code>bootm</code> 还支持 FIT 镜像（Flattened Image Tree），这是一种新的镜像格式，把内核、设备树、ramdisk 打包在一起，还支持签名和加密。FIT 镜像更灵活也更安全，是未来的趋势，但目前很多项目还在用 Legacy 格式，因为简单。</p><h3 id="启动流程细节" tabindex="-1">启动流程细节 <a class="header-anchor" href="#启动流程细节" aria-label="Permalink to &quot;启动流程细节&quot;">​</a></h3><p>无论是 <code>bootm</code> 还是 <code>bootz</code>，启动流程都分几个阶段。第一阶段是镜像验证，检查魔数、CRC 校验和，确保镜像没有损坏。第二阶段是解压和加载，zImage 需要解压，uImage 可能在正确的位置。第三阶段是设备树处理，把设备树放到内核期望的位置。第四阶段是准备启动参数，设置 ATAGS 或者设备树。最后阶段是跳转到内核。</p><p>这个流程中，设备树处理很关键。内核需要知道硬件信息，比如内存布局、外设地址、中断号等，这些都在设备树里描述。U-Boot 要把设备树放到正确的位置，还要根据实际情况修改某些属性，比如 chosen 节点的 bootargs。</p><h2 id="环境变量管理-printenv、setenv、saveenv" tabindex="-1">环境变量管理：printenv、setenv、saveenv <a class="header-anchor" href="#环境变量管理-printenv、setenv、saveenv" aria-label="Permalink to &quot;环境变量管理：printenv、setenv、saveenv&quot;">​</a></h2><p>U-Boot 的环境变量是配置系统的核心。它就像一个全局的配置数据库，存储了启动参数、网络配置、设备信息等。掌握环境变量管理，就掌握了 U-Boot 的&quot;配置中心&quot;。</p><h3 id="printenv-查看变量" tabindex="-1">printenv 查看变量 <a class="header-anchor" href="#printenv-查看变量" aria-label="Permalink to &quot;printenv 查看变量&quot;">​</a></h3><p><code>printenv</code> 命令显示环境变量：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; printenv</span></span>
<span class="line"><span>arch=arm</span></span>
<span class="line"><span>baudrate=115200</span></span>
<span class="line"><span>board=mx6ull_14x14_evk</span></span>
<span class="line"><span>board_name=mx6ull_14x14_evk</span></span>
<span class="line"><span>bootargs=console=ttymxc0,115200 root=/dev/mmcblk1p2 rootwait rw</span></span>
<span class="line"><span>bootcmd=mmc dev 1; mmc read 0x82000000 0x800 0x4000; bootz 0x82000000 - 0x88000000</span></span>
<span class="line"><span>bootdelay=3</span></span>
<span class="line"><span>...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>这是显示所有变量。你也可以指定只看某个变量：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; printenv bootargs</span></span>
<span class="line"><span>bootargs=console=ttymxc0,115200 root=/dev/mmcblk1p2 rootwait rw</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>有个隐藏选项 <code>-a</code> 可以显示以点开头的变量，这些通常是系统内部变量，平时用不上：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; printenv -a</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="setenv-设置变量" tabindex="-1">setenv 设置变量 <a class="header-anchor" href="#setenv-设置变量" aria-label="Permalink to &quot;setenv 设置变量&quot;">​</a></h3><p><code>setenv</code> 命令设置环境变量：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; setenv ipaddr 192.168.1.100</span></span>
<span class="line"><span>=&gt; setenv serverip 192.168.1.1</span></span>
<span class="line"><span>=&gt; setenv bootdelay 5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>设置后会立即生效，但不会永久保存，重启后会丢失。要永久保存需要用 <code>saveenv</code> 命令，我们后面会讲。</p><p><code>setenv</code> 还可以删除变量，赋值为空就行：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; setenv oldvar</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这会删除 <code>oldvar</code> 变量。有个陷阱要注意，你不能直接 <code>setenv bootargs</code> 来删除 bootargs，这样会把它设为空字符串，而不是删除。要删除的话用 <code>setenv bootargs &amp;&amp; saveenv</code>，或者直接编辑存储设备上的环境变量区域。</p><h3 id="saveenv-保存变量" tabindex="-1">saveenv 保存变量 <a class="header-anchor" href="#saveenv-保存变量" aria-label="Permalink to &quot;saveenv 保存变量&quot;">​</a></h3><p><code>saveenv</code> 命令把当前环境变量保存到存储设备：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; saveenv</span></span>
<span class="line"><span>Saving Environment to MMC...</span></span>
<span class="line"><span>Writing to MMC(1)... done</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这个命令很关键，不然你设置的环境变量重启后就没了。保存位置通常在 eMMC 或者 SD 卡的某个固定区域，具体位置看配置。</p><p>如果你发现保存失败，可能是存储设备写保护了，或者环境变量区域满了。eMMC 有时候会有写保护位，需要先清除。环境变量区域大小是固定的，如果变量太多超出了大小，saveenv 会失败，这时候得删掉一些不用的变量。</p><h3 id="环境变量存储格式" tabindex="-1">环境变量存储格式 <a class="header-anchor" href="#环境变量存储格式" aria-label="Permalink to &quot;环境变量存储格式&quot;">​</a></h3><p>环境变量在存储设备上是有特定格式的。开头是一个 32 位的 CRC 校验和，然后是一系列 &quot;name=value&quot; 字符串，用 null 字符分隔，最后用两个 null 字符表示结束。U-Boot 启动时会读取这个区域，计算 CRC 校验和，如果正确就加载到内存。</p><p>这种设计的好处是简单可靠，但缺点是大小固定，用起来不够灵活。新版本的 U-Boot 支持环境变量重叠和多个存储位置，可以提高可靠性，但基本格式还是一样的。</p><h2 id="控制台信息-coninfo-命令" tabindex="-1">控制台信息：coninfo 命令 <a class="header-anchor" href="#控制台信息-coninfo-命令" aria-label="Permalink to &quot;控制台信息：coninfo 命令&quot;">​</a></h2><p><code>coninfo</code> 命令显示控制台设备信息：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; coninfo</span></span>
<span class="line"><span>List of available devices</span></span>
<span class="line"><span>|-- serial</span></span>
<span class="line"><span>|   |-- stdin</span></span>
<span class="line"><span>|   |-- stdout</span></span>
<span class="line"><span>|   |-- stderr</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这里显示当前有三个标准 IO 设备：stdin（标准输入）、stdout（标准输出）、stderr（标准错误），都映射到了串口设备。</p><p>如果你有多个串口或者同时有串口和 LCD 显示器，<code>coninfo</code> 会显示更多设备：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; coninfo</span></span>
<span class="line"><span>List of available devices</span></span>
<span class="line"><span>|-- serial</span></span>
<span class="line"><span>|   |-- stdin</span></span>
<span class="line"><span>|   |-- stdout</span></span>
<span class="line"><span>|   |-- stderr</span></span>
<span class="line"><span>|-- vidconsole</span></span>
<span class="line"><span>|-- serial@021f0000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><code>I</code> 标志表示该设备可以作输入，<code>O</code> 标志表示可以作输出。你可以用 <code>console</code> 命令或者修改环境变量来切换控制台设备。</p><p>控制台切换的一个实用场景是调试多串口系统。比如你有调试串口和通信串口，想通过通信串口输出日志，就可以用 coninfo 看看设备名，然后修改 <code>stdout</code> 环境变量。</p><h2 id="设备树操作-fdt-命令" tabindex="-1">设备树操作：fdt 命令 <a class="header-anchor" href="#设备树操作-fdt-命令" aria-label="Permalink to &quot;设备树操作：fdt 命令&quot;">​</a></h2><p>设备树是现代 Linux 系统描述硬件的标准方式，U-Boot 提供了 <code>fdt</code> 命令来操作设备树。这个命令功能很强大，可以查看、修改、添加节点和属性。</p><h3 id="fdt-addr-和-fdt-print" tabindex="-1">fdt addr 和 fdt print <a class="header-anchor" href="#fdt-addr-和-fdt-print" aria-label="Permalink to &quot;fdt addr 和 fdt print&quot;">​</a></h3><p>先用 <code>fdt addr</code> 设置设备树地址：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; fdt addr 0x88000000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后用 <code>fdt print</code> 查看设备树内容：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; fdt print /</span></span>
<span class="line"><span>/ {</span></span>
<span class="line"><span>    model = &quot;Freescale i.MX6 UltraLite 14x14 EVK Board&quot;;</span></span>
<span class="line"><span>    compatible = &quot;fsl,imx6ull-14x14-evk&quot;, &quot;fsl,imx6ull&quot;;</span></span>
<span class="line"><span>    #address-cells = &lt;0x00000001&gt;;</span></span>
<span class="line"><span>    #size-cells = &lt;0x00000001&gt;;</span></span>
<span class="line"><span>    ...</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>你也可以只看某个节点：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; fdt print /memory</span></span>
<span class="line"><span>memory {</span></span>
<span class="line"><span>    device_type = &quot;memory&quot;;</span></span>
<span class="line"><span>    reg = &lt;0x80000000 0x20000000&gt;;</span></span>
<span class="line"><span>};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>或者只看某个属性：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; fdt print /memory reg</span></span>
<span class="line"><span>reg = &lt;0x80000000 0x20000000&gt;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>fdt list</code> 类似 <code>fdt print</code>，但只显示一级子节点，不递归显示：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; fdt list /</span></span>
<span class="line"><span>/ {</span></span>
<span class="line"><span>    aliases { ... };</span></span>
<span class="line"><span>    chosen { ... };</span></span>
<span class="line"><span>    cpus { ... };</span></span>
<span class="line"><span>    memory { ... };</span></span>
<span class="line"><span>    soc { ... };</span></span>
<span class="line"><span>};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="fdt-set-和-fdt-mknode" tabindex="-1">fdt set 和 fdt mknode <a class="header-anchor" href="#fdt-set-和-fdt-mknode" aria-label="Permalink to &quot;fdt set 和 fdt mknode&quot;">​</a></h3><p><code>fdt set</code> 修改属性值：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; fdt set /memory reg &lt;0x80000000 0x40000000&gt;</span></span>
<span class="line"><span>=&gt; fdt set /chosen bootargs &quot;console=ttymxc0,115200 root=/dev/mmcblk1p2&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>第一个命令修改内存大小为 1GB，第二个命令设置启动参数。注意属性值的格式，数字用尖括号括起来，字符串直接写。</p><p><code>fdt mknode</code> 创建新节点：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; fdt mknode /soc mydevice</span></span>
<span class="line"><span>=&gt; fdt set /soc/mydevice compatible &quot;vendor,mydevice&quot;</span></span>
<span class="line"><span>=&gt; fdt set /soc/mydevice reg &lt;0x021f0000 0x4000&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这会创建一个新设备节点，设置 compatible 和 reg 属性。这在测试新硬件或者临时修改设备树时很有用，不用重新编译设备树就能生效。</p><h3 id="fdt-get-和-fdt-rm" tabindex="-1">fdt get 和 fdt rm <a class="header-anchor" href="#fdt-get-和-fdt-rm" aria-label="Permalink to &quot;fdt get 和 fdt rm&quot;">​</a></h3><p><code>fdt get</code> 读取属性值到环境变量：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; fdt get memsize /memory reg</span></span>
<span class="line"><span>=&gt; printenv memsize</span></span>
<span class="line"><span>memsize=0x80000000 0x20000000</span></span>
<span class="line"><span>=&gt; fdt get addr myvar /soc/mydevice reg</span></span>
<span class="line"><span>=&gt; printenv myvar</span></span>
<span class="line"><span>myvar=0x021f0000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>第一个命令读取整个 reg 属性，第二个命令只读取第一个值。你可以在脚本里用这个命令提取设备树信息，然后根据这些信息做相应操作。</p><p><code>fdt rm</code> 删除节点或属性：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; fdt rm /soc/olddevice</span></span>
<span class="line"><span>=&gt; fdt rm /chosen bootargs</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>第一个命令删除整个节点，第二个命令删除一个属性。这在调试时很有用，比如你怀疑某个设备导致问题，可以先删除它的节点看看。</p><h3 id="fdt-apply-和-fdt-resize" tabindex="-1">fdt apply 和 fdt resize <a class="header-anchor" href="#fdt-apply-和-fdt-resize" aria-label="Permalink to &quot;fdt apply 和 fdt resize&quot;">​</a></h3><p><code>fdt apply</code> 应用设备树叠加（overlay）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; fdt apply 0x89000000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>设备树叠加是一种在不修改主设备树的情况下添加或修改节点的方式，很适合模块化设计。比如你有多个硬件配置，每个配置一个叠加文件，启动时根据实际情况选择应用哪个。</p><p><code>fdt resize</code> 调整设备树大小：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; fdt resize 0x1000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>添加节点或属性后，设备树可能会变大，超出原来分配的空间，这时候需要用 resize 命令扩展。参数是额外的空间大小，按需调整。</p><h2 id="调试技巧和窍门" tabindex="-1">调试技巧和窍门 <a class="header-anchor" href="#调试技巧和窍门" aria-label="Permalink to &quot;调试技巧和窍门&quot;">​</a></h2><p>讲了这么多命令，现在分享一些实战中总结的调试技巧。这些技巧不是命令文档会写的，都是踩坑后总结出来的经验。</p><h3 id="分段验证法" tabindex="-1">分段验证法 <a class="header-anchor" href="#分段验证法" aria-label="Permalink to &quot;分段验证法&quot;">​</a></h3><p>遇到问题不要一头扎进去，要分段验证。比如网络启动失败，先验证网络通不通，再验证 TFTP 服务器有没有问题，最后验证镜像对不对。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; ping 192.168.1.1              # 1. 测试网络</span></span>
<span class="line"><span>=&gt; tftp 0x82000000 test.txt      # 2. 测试 TFTP</span></span>
<span class="line"><span>=&gt; tftp 0x82000000 zImage        # 3. 下载镜像</span></span>
<span class="line"><span>=&gt; iminfo 0x82000000             # 4. 验证镜像</span></span>
<span class="line"><span>=&gt; bootz 0x82000000 - 0x88000000 # 5. 启动内核</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>如果第 1 步就失败了，问题在网卡或者网线，不用浪费时间看 TFTP。如果第 2 步失败，问题在 TFTP 服务器配置。如果第 4 步失败，问题在镜像文件。这样一步步排查，很快就能定位到问题。</p><h3 id="环境变量备份" tabindex="-1">环境变量备份 <a class="header-anchor" href="#环境变量备份" aria-label="Permalink to &quot;环境变量备份&quot;">​</a></h3><p>修改环境变量前先备份，特别是 <code>bootargs</code> 和 <code>bootcmd</code> 这种关键变量：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; setenv bootargs_backup \${bootargs}</span></span>
<span class="line"><span>=&gt; setenv bootcmd_backup \${bootcmd}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这样改错了还能恢复：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; setenv bootargs \${bootargs_backup}</span></span>
<span class="line"><span>=&gt; setenv bootcmd \${bootcmd_backup}</span></span>
<span class="line"><span>=&gt; saveenv</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>我吃过这个亏，改了 bootargs 结果起不来，又忘了原来的值，只能重新烧录。从那以后我养成了备份的习惯，改之前先保存一份。</p><h3 id="日志收集" tabindex="-1">日志收集 <a class="header-anchor" href="#日志收集" aria-label="Permalink to &quot;日志收集&quot;">​</a></h3><p>调试时多收集日志，不要只盯着报错信息看。串口输出从头到尾都保存下来，很多问题的线索在早期的初始化阶段就出现了。</p><p>可以用脚本自动收集日志，比如：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">picocom</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 115200</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/ttyUSB0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tee</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uboot.log</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这样串口输出会同时显示在终端和保存到 <code>uboot.log</code> 文件。出问题时可以直接看日志，不用凭记忆回忆。</p><h3 id="最小化配置" tabindex="-1">最小化配置 <a class="header-anchor" href="#最小化配置" aria-label="Permalink to &quot;最小化配置&quot;">​</a></h3><p>怀疑某个配置导致问题时，先最小化配置。比如启动失败，试试最简单的 bootargs：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; setenv bootargs &quot;console=ttymxc0,115200&quot;</span></span>
<span class="line"><span>=&gt; bootz 0x82000000 - 0x88000000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果这样能起来，说明是原来的 bootargs 有问题，慢慢加参数找原因。如果这样都不行，问题可能在内核或者设备树。</p><h3 id="比较法" tabindex="-1">比较法 <a class="header-anchor" href="#比较法" aria-label="Permalink to &quot;比较法&quot;">​</a></h3><p>有块工作正常的板子是最好的参照。同样的命令、同样的环境变量、同样的镜像，对比一下哪里不一样：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; printenv &gt; env1.txt      # 问题板子的环境变量</span></span>
<span class="line"><span>=&gt; printenv &gt; env2.txt      # 正常板子的环境变量</span></span>
<span class="line"><span>=&gt; diff env1.txt env2.txt   # 找差异</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这个方法很土但很有效，我遇到过环境变量有个字符打错了导致启动失败的情况，对比一下马上就发现了。</p><h2 id="常见错误及解决方案" tabindex="-1">常见错误及解决方案 <a class="header-anchor" href="#常见错误及解决方案" aria-label="Permalink to &quot;常见错误及解决方案&quot;">​</a></h2><p>最后整理一些常见的错误和解决办法，这些是笔者在实战中反复遇到过的。</p><h3 id="bad-magic-number" tabindex="-1">&quot;Bad Magic Number&quot; <a class="header-anchor" href="#bad-magic-number" aria-label="Permalink to &quot;&quot;Bad Magic Number&quot;&quot;">​</a></h3><p>这个错误表示镜像格式不对。可能原因：下载了错误的文件、传输过程中损坏、地址传错了。</p><p>解决方法：用 <code>iminfo</code> 命令检查镜像格式：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; iminfo 0x82000000</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Checking Image at 82000000 ...</span></span>
<span class="line"><span>   Bad Magic Number</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>如果显示这个，说明该地址没有有效镜像。检查一下下载地址对不对，重新下载试试。</p><h3 id="crc-error" tabindex="-1">&quot;CRC error&quot; <a class="header-anchor" href="#crc-error" aria-label="Permalink to &quot;&quot;CRC error&quot;&quot;">​</a></h3><p>CRC 校验失败，说明镜像文件损坏。可能原因：传输错误、存储设备坏块、文件本身有问题。</p><p>解决方法：重新下载文件，如果还是不行，换一个下载源或者下载工具。也可以尝试换个存储设备试试。</p><h3 id="no-mmc-device-available" tabindex="-1">&quot;No MMC device available&quot; <a class="header-anchor" href="#no-mmc-device-available" aria-label="Permalink to &quot;&quot;No MMC device available&quot;&quot;">​</a></h3><p>找不到 MMC 设备。可能原因：硬件问题、驱动没加载、设备号不对。</p><p>解决方法：先用 <code>mmc list</code> 看看有哪些设备：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; mmc list</span></span>
<span class="line"><span>FSL_SDHC: 0 (eMMC)</span></span>
<span class="line"><span>FSL_SDHC: 1 (SD)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>然后切换到正确的设备：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; mmc dev 0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果还是不行，检查硬件连接，看看焊接是不是有问题。</p><h3 id="tftp-timeout" tabindex="-1">&quot;TFTP timeout&quot; <a class="header-anchor" href="#tftp-timeout" aria-label="Permalink to &quot;&quot;TFTP timeout&quot;&quot;">​</a></h3><p>TFTP 下载超时。可能原因：网络不通、TFTP 服务器没启动、文件路径不对、防火墙阻止。</p><p>解决方法：先 ping 服务器确认网络通：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; ping 192.168.1.1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后检查 TFTP 服务器状态和文件路径。Linux 下可以查看服务器日志：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tftpd-hpa</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="kernel-panic-not-syncing" tabindex="-1">&quot;Kernel panic - not syncing&quot; <a class="header-anchor" href="#kernel-panic-not-syncing" aria-label="Permalink to &quot;&quot;Kernel panic - not syncing&quot;&quot;">​</a></h3><p>内核启动时崩溃。可能原因：bootargs 不对、设备树不匹配、内存地址冲突、驱动问题。</p><p>解决方法：先简化 bootargs：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; setenv bootargs &quot;console=ttymxc0,115200&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果能启动，说明原来的 bootargs 有问题。如果还是不行，可能是设备树的问题，用 <code>fdt print</code> 检查一下。</p><h3 id="environment-exceeds-reserved-area" tabindex="-1">&quot;Environment exceeds reserved area&quot; <a class="header-anchor" href="#environment-exceeds-reserved-area" aria-label="Permalink to &quot;&quot;Environment exceeds reserved area&quot;&quot;">​</a></h3><p>环境变量空间不足。可能原因：变量太多、某个变量值太大。</p><p>解决方法：删除一些不需要的变量，或者增大环境变量区域。增大区域需要修改配置重新编译，这个比较麻烦，优先考虑清理不需要的变量。</p><h2 id="实战调试案例" tabindex="-1">实战调试案例 <a class="header-anchor" href="#实战调试案例" aria-label="Permalink to &quot;实战调试案例&quot;">​</a></h2><p>最后来两个实战案例，看看怎么综合运用这些命令解决问题。</p><h3 id="案例一-网络启动失败" tabindex="-1">案例一：网络启动失败 <a class="header-anchor" href="#案例一-网络启动失败" aria-label="Permalink to &quot;案例一：网络启动失败&quot;">​</a></h3><p>现象：tftp 下载总是超时，ping 服务器正常。</p><p>排查过程：</p><ol><li>先确认网络通：</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; ping 192.168.1.1</span></span>
<span class="line"><span>host 192.168.1.1 is alive</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ol start="2"><li><p>检查 TFTP 服务器，发现服务器配置正常，文件也存在。</p></li><li><p>尝试下载一个小文件：</p></li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; tftp 0x82000000 test.txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>成功了！说明 TFTP 本身没问题，问题在文件太大。</p><ol start="4"><li>检查文件大小：</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; iminfo 0x82000000</span></span>
<span class="line"><span>Image Name:   Linux-5.15.0</span></span>
<span class="line"><span>Data Size:   6821504 Bytes = 6.5 MiB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>6.5MB 不算大啊，为什么超时？</p><ol start="5"><li>怀疑是超时时间设置问题，检查环境变量：</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; printenv netretry</span></span>
<span class="line"><span>netretry=no</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>原来是设置了网络不重试，一次超时就放弃。修改一下：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; setenv netretry yes</span></span>
<span class="line"><span>=&gt; saveenv</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>再试一次，成功了！</p><h3 id="案例二-内核启动后立刻重启" tabindex="-1">案例二：内核启动后立刻重启 <a class="header-anchor" href="#案例二-内核启动后立刻重启" aria-label="Permalink to &quot;案例二：内核启动后立刻重启&quot;">​</a></h3><p>现象：bootz 启动内核后，看到 &quot;Starting kernel ...&quot; 就重启，没有更多输出。</p><p>排查过程：</p><ol><li>先简化 bootargs：</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; setenv bootargs &quot;console=ttymxc0,115200&quot;</span></span>
<span class="line"><span>=&gt; bootz 0x82000000 - 0x88000000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>还是重启，说明不是 bootargs 的问题。</p><ol start="2"><li>检查设备树：</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; fdt print /memory</span></span>
<span class="line"><span>memory {</span></span>
<span class="line"><span>    device_type = &quot;memory&quot;;</span></span>
<span class="line"><span>    reg = &lt;0x80000000 0x20000000&gt;;</span></span>
<span class="line"><span>};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>内存配置看起来没问题。</p><ol start="3"><li>检查 CPU 频率设置：</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; fdt print /cpu@0</span></span>
<span class="line"><span>cpu@0 {</span></span>
<span class="line"><span>    ...</span></span>
<span class="line"><span>    clock-frequency = &lt;0x47868c00&gt;;</span></span>
<span class="line"><span>};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这个频率有点高啊，换算一下是 1.2GHz，i.MX6ULL 最高 900MHz，可能是频率设置不对导致 CPU 过热或者不稳定。</p><ol start="4"><li>修改设备树：</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; fdt set /cpu@0 clock-frequency &lt;0x35a4e900&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>设为 900MHz，再启动：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=&gt; bootz 0x82000000 - 0x88000000</span></span>
<span class="line"><span>Starting kernel ...</span></span>
<span class="line"><span>[    0.000000] Booting Linux on physical CPU 0x0</span></span>
<span class="line"><span>[    0.000000] Linux version 5.15.0 ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>成功了！原来是设备树里 CPU 频率设置错误导致的。</p><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h2><p>到这里，U-Boot 调试命令的主要内容就讲完了。从板子信息查询到存储操作，从网络启动到内核引导，从环境变量管理到设备树操作，我们系统性地过了一遍。</p><p>掌握这些命令不是靠死记硬背，而是要在实战中不断练习。每次遇到问题，先尝试用命令定位，而不是盲目的改代码或者烧录。时间久了，你会形成一种直觉，知道该用哪个命令，该检查什么。</p><p>命令行调试不是老派的做法，而是嵌入式开发的基本功。JTAG 很强大，但不是每次都方便用；IDE 很友好，但有时候不如命令行直接。一个好的工程师，应该掌握各种调试方法，根据实际情况选择最合适的工具。</p><p>希望这篇文章能帮你建立起对 U-Boot 命令行调试的系统认识，下次遇到问题时，能冷静地敲几个命令，快速定位到原因。调试不是碰运气，而是有方法的，掌握了正确的方法，问题就解决了一半。</p><hr><p>至此，我们的U-Boot移植教程系列就告一段落了。从认识U-Boot的基础架构，到编译出第一个镜像；从板级配置和设备树移植，到LCD和网络这些复杂外设的驱动适配；再到Logo显示和调试命令的使用——你已经掌握了一套完整的U-Boot移植技能。</p><p>这些技能不是孤立的，它们构成了一个完整的知识体系。理解了编译流程，你就知道每次修改后应该如何正确地构建；掌握了设备树，你就具备了硬件描述与代码分离的现代思维；调通了网络，你的开发效率会成倍提升；熟悉了调试命令，你就能从容应对各种突发问题。</p><p>嵌入式开发没有银弹，但有方法论。掌握了正确的方法，再复杂的系统也能拆解成可管理的部分。希望这个教程系列能成为你U-Boot学习之路上的垫脚石，让你从&quot;照着做&quot;到&quot;理解为什么&quot;，再到&quot;能独立解决新问题&quot;。</p><p>祝你在嵌入式开发的道路上越走越远！</p>`,253)])])}const m=a(i,[["render",l]]);export{u as __pageData,m as default};
